import{_ as t,c as i,o as s,ag as a}from"./chunks/framework.CSeR4K32.js";const u=JSON.parse('{"title":"Main PVE Installation","description":"","frontmatter":{"outline":"deep","head":[["link",{"rel":"canonical","href":"https://www.spiritlhl.net/en/guide/pve/pve_install.html"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:site_name","content":"OneClickVirt"}],["meta",{"property":"og:locale","content":"en_US"}],["meta",{"property":"og:title","content":"Main PVE Installation"}],["meta",{"property":"og:url","content":"https://www.spiritlhl.net/en/guide/pve/pve_install.html"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Main PVE Installation"}]]},"headers":[],"relativePath":"en/guide/pve/pve_install.md","filePath":"en/guide/pve/pve_install.md","lastUpdated":1782998985000}'),n={name:"en/guide/pve/pve_install.md"};function o(l,e,r,p,h,d){return s(),i("div",null,e[0]||(e[0]=[a(`<h1 id="main-pve-installation" tabindex="-1">Main PVE Installation <a class="header-anchor" href="#main-pve-installation" aria-label="Permalink to &quot;Main PVE Installation&quot;">​</a></h1><p>If you are not sure how to answer an installation prompt, pressing Enter for the default option is usually fine.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>For low-configuration hosts, it is recommended to check the contents of the <code>Custom</code> partition after all the content has been installed to perform memory tuning and reduce the memory footprint.</p></div><h2 id="installation-on-non-physical-machines" tabindex="-1">Installation on non-physical machines <a class="header-anchor" href="#installation-on-non-physical-machines" aria-label="Permalink to &quot;Installation on non-physical machines&quot;">​</a></h2><p>Proxmox installed by this method can subsequently use all scripts of this project.</p><h3 id="one-click-pve-installation" tabindex="-1">One-click PVE installation <a class="header-anchor" href="#one-click-pve-installation" aria-label="Permalink to &quot;One-click PVE installation&quot;">​</a></h3><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Debian 12 or newer is recommended. In real tests, some Debian 11 hosts lost network connectivity after reboot, while Debian 12 did not show this issue.</p></div><ul><li>Installs the latest available PVE package set from apt sources.</li><li>Example mapping: Debian 10 -&gt; PVE 6.4, Debian 11 -&gt; PVE 7.x, Debian 12 -&gt; PVE 8.x, Debian 13 -&gt; PVE 9.x.</li><li>Updates <code>/etc/hosts</code> to fix host naming issues and inject required PVE entries.</li><li>Updates <code>/etc/cloud/cloud.cfg</code> to avoid cloud-init overwriting modified host settings.</li><li>Updates <code>/etc/network/interfaces</code> to convert DHCP-style defaults to static layout and add vmbr0 gateway config.</li><li>Automatically adjusts package source handling and DNS settings during installation to reduce avoidable network failures</li><li>Creates vmbr0 (independent IP gateway) and auto-detects whether host address/gateway are private or public.</li><li>vmbr0 setup supports IPv4-only, IPv6-only, and dual-stack VM networking with automatic subnet recognition.</li><li>Installs required toolkits for VM provisioning on PVE.</li><li>On x86_64, replaces enterprise apt subscription sources with community sources; ARM paths use maintained patch workflows.</li><li>Prints Linux kernel and PVE kernel installation status for quick verification.</li><li>Enables boot-time DNS health checks through systemd service.</li><li>Adds PVE apt sources and prints login access details after installation.</li></ul><p>All modified files have been set to read-only mode to avoid overwriting after reboot.</p><p>If you need to edit these files later, run <code>chattr -i &lt;file&gt;</code> first to remove read-only protection, then run <code>chattr +i &lt;file&gt;</code> after editing.</p><p>During execution, you may be prompted to reboot once. After reboot, wait at least 20 seconds to confirm there is no additional automatic reboot.</p><p>Some source environments are missing <code>ifupdown</code> or <code>ifupdown2</code>. The installer may deploy helper components and trigger an additional reboot. Wait about 20 seconds after boot to confirm no further automatic reboot is pending.</p><p>If the host already has an SLAAC-assigned IPv6 address, you can choose whether to use the largest detected IPv6 subnet range. The default Enter option keeps local IPv6 only. If you plan to assign independent IPv6 addresses to VMs/containers later, choose <code>y</code>.</p><p>For non-interactive installation, use <code>export noninteractive=true</code> before the install command. The script will apply default choices for optional prompts.</p><p>Command:</p><div class="language-shell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -L</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/oneclickvirt/pve/main/scripts/install_pve.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install_pve.sh</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chmod</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +x</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install_pve.sh</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install_pve.sh</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>or</p><div class="language-shell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install_pve.sh</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Non-interactive example after downloading the script:</p><div class="language-shell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> noninteractive</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">true &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install_pve.sh</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>After installation, the browser may show a certificate warning. Click Advanced (or equivalent) and continue if you trust the host.</p></div><p>The login information is your SSH account and password.</p><h3 id="pre-configure-the-environment" tabindex="-1">Pre-configure the environment <a class="header-anchor" href="#pre-configure-the-environment" aria-label="Permalink to &quot;Pre-configure the environment&quot;">​</a></h3><ul><li>Creating a resource pool mypool</li><li>Remove the subscription popup</li><li>Attempt to enable hardware passthrough</li><li>Detect and auto-install AppArmor modules.</li><li>Before rebooting, consider deploying <a href="https://github.com/naiba/nezha" target="_blank" rel="noreferrer">nezha probe</a> so you still have emergency command-line access if SSH becomes unavailable.</li><li>Before running <code>reboot</code>, make sure all background apt tasks are finished. Some hosts process apt jobs slowly.</li></ul><p>Command:</p><div class="language-shell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &lt;(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sSLk</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/oneclickvirt/pve/main/scripts/build_backend.sh)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="automatically-configure-the-host-s-gateway" tabindex="-1">Automatically configure the host&#39;s gateway <a class="header-anchor" href="#automatically-configure-the-host-s-gateway" aria-label="Permalink to &quot;Automatically configure the host&#39;s gateway&quot;">​</a></h3><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Before using this command, make sure the server has rebooted and the PVE web terminal is working. Do not run it immediately after reboot; wait at least 1 minute after the web terminal is available. If the web service does not start, run <code>systemctl status pveproxy</code> to check status. If it is stuck, run <code>systemctl start pveproxy</code>.</p></div><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>This step can cause SSH disconnections if networking changes are applied before the PVE kernel stack is fully ready. Wait a few minutes and confirm the web UI is healthy before execution.</p></div><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>If the host needs an IPv6 tunnel (to attach an IPv6 subnet on a host without native IPv6), see <a href="https://www.spiritlhl.net/en/guide/incus/incus_custom.html#attach-free-ipv6-address-segments-to-host-machines" target="_blank" rel="noreferrer">IPv6 free subnet attachment</a>. In that guide, skip the &quot;initial environment modifications&quot; section, apply only the tunnel attachment steps, confirm IPv6 is available, then run the gateway configuration command below.</p></div><ul><li>If vmbr0 is not created, it is automatically created with the same logic as the main installation</li><li>Create vmbr1 (NAT gateway) to support IPv4 servers that open NAT for IPv6 networks with NAT.</li><li>Create vmbr2 (standalone IPv6 gateway). <code>ndppd</code> is used to handle host-side MAC verification for IPv6 addresses so standalone IPv6 server networking can work correctly.</li><li>To review full network settings, run <code>cat /etc/network/interfaces</code>. If you need to change gateway settings, edit this file directly; the web UI cannot apply those changes reliably.</li><li>Load iptables and set back to source and allow NAT port forwarding.</li></ul><p>In short, <code>vmbr0</code> is responsible for v4 standalone IPs, and <code>vmbr1</code> is responsible for complex v4/v6 NATs, <code>vmbr2</code> is responsible for v6 standalone IPs.</p><p>For independent IPv4 VMs on <code>vmbr0</code>, use the same subnet and netmask as the host, and assign an unbound host-side IPv4 as the VM IPv4/CIDR. If you always use the provided scripts, you usually do not need to handle this manually.</p><p>For NAT IPv4 VMs on <code>vmbr1</code>, use gateway <code>172.16.1.1</code> and subnet <code>172.16.1.x/24</code> (where <code>x</code> must not be <code>1</code>). Script-based workflows handle this automatically.</p><p>Command:</p><div class="language-shell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &lt;(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sSLk</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/oneclickvirt/pve/main/scripts/build_nat_network.sh)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>This step may require you to reboot your system after a few minutes of successful execution, see the final execution of the script at the end of the tip. However, a reboot will ensure that some of the hidden settings are loaded successfully, so be sure to reboot the server once if you are in a position to do so.</p></div><p>To this point the main body is installed.</p><h3 id="one-click-uninstall-pve" tabindex="-1">One-Click Uninstall PVE <a class="header-anchor" href="#one-click-uninstall-pve" aria-label="Permalink to &quot;One-Click Uninstall PVE&quot;">​</a></h3><p>After the uninstall script completes, restarting the host machine will restore it to its pre-installation state.</p><div class="language-shell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &lt;(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sSLk</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/oneclickvirt/pve/main/scripts/uninstall_pve.sh)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="installation-on-a-physical-machine" tabindex="-1">Installation on a physical machine <a class="header-anchor" href="#installation-on-a-physical-machine" aria-label="Permalink to &quot;Installation on a physical machine&quot;">​</a></h2><p>Proxmox installed through this physical-machine path is <strong>not</strong> guaranteed to be compatible with all automation scripts in this project.</p><p>This method has not been widely validated. Current validation is based on local PVE 8.4 installs in fixed-IP router environments. If issues occur, please open an issue in the repository.</p><h3 id="u-disk-burning-official-iso" tabindex="-1">U disk burning official ISO <a class="header-anchor" href="#u-disk-burning-official-iso" aria-label="Permalink to &quot;U disk burning official ISO&quot;">​</a></h3><p>Official ISO download address:</p><p><a href="https://www.proxmox.com/en/downloads/proxmox-virtual-environment/iso" target="_blank" rel="noreferrer">https://www.proxmox.com/en/downloads/proxmox-virtual-environment/iso</a></p><p>You need to download it locally in advance.</p><p>You also need a USB flash drive with a good read/write rate for making a boot disk, as the boot disk needs to be formatted using rufus for boot disk making, you need to make sure that the USB flash drive is empty before making the disk</p><p>rufus download address (download to your local, not USB flash drive):</p><p><a href="https://rufus.ie/zh/" target="_blank" rel="noreferrer">https://rufus.ie/zh/</a></p><p>or</p><p><a href="https://github.com/pbatard/rufus" target="_blank" rel="noreferrer">https://github.com/pbatard/rufus</a></p><p>Burning needs to use DD method to burn, the original data of the USB flash disk will be completely erased after burning.</p><h3 id="pve-installation" tabindex="-1">PVE installation <a class="header-anchor" href="#pve-installation" aria-label="Permalink to &quot;PVE installation&quot;">​</a></h3><p>Find out how to get into the BIOS on the host itself, and modify two things after entering the BIOS</p><ol><li><p>Safe boot needs to be turned off</p></li><li><p>the order of the boot needs to be moved to the first USB order</p></li></ol><p>Then save the settings, then insert the USB flash drive, reboot the system, and choose to use the graphical interface for installation.</p><p>For FQDN, enter a hostname such as <code>pve.example.com</code>. A subdomain of your own domain is recommended. It does not have to resolve publicly during initial setup.</p><p>After installation, the machine reboots automatically. When the screen goes black, unplug the USB drive to avoid booting into installer again. If you forget, shut down, unplug USB, and start again.</p><h3 id="wireless-network-configuration" tabindex="-1">Wireless Network Configuration <a class="header-anchor" href="#wireless-network-configuration" aria-label="Permalink to &quot;Wireless Network Configuration&quot;">​</a></h3><p>Download the required zip file and shell scripts</p><p><a href="https://raw.githubusercontent.com/oneclickvirt/pve/refs/heads/main/extra_scripts/wireless/wireless.zip" target="_blank" rel="noreferrer">https://raw.githubusercontent.com/oneclickvirt/pve/refs/heads/main/extra_scripts/wireless/wireless.zip</a></p><p><a href="https://raw.githubusercontent.com/oneclickvirt/pve/refs/heads/main/extra_scripts/wireless/wireless.sh" target="_blank" rel="noreferrer">https://raw.githubusercontent.com/oneclickvirt/pve/refs/heads/main/extra_scripts/wireless/wireless.sh</a></p><p>After downloading, unzip the zip file, drag the <code>wireless</code> folder into the root directory of a new USB flash drive, and the <code>wireless.sh</code> file has to be put into the root directory as well.</p><p>After the flash drive is plugged into the physical machine, you need to mount the flash drive, here sdx1 is the actual path of the flash drive queried by the first command, you need to modify it yourself</p><div class="language-shell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">fdisk</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -l</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> </span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mount</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/sdx1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /mnt</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>The <code>wireless.zip</code> on the USB flash drive should be unzipped and opened to see the deb file.</p><p>At this point, run the one-click configuration</p><div class="language-shell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /mnt/wireless.sh</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>After the configuration is complete, the system will automatically reboot and the public network will be available after the reboot.</p><p>During the execution of the configuration script, you will be prompted to enter the name and password of the WIFI. Since there is no Chinese input method in the pure CI environment, the name of the WIFI must be composed of English numbers only, and the password must be the same.</p><h3 id="cautions" tabindex="-1">Cautions <a class="header-anchor" href="#cautions" aria-label="Permalink to &quot;Cautions&quot;">​</a></h3><p>For physical-machine installs with wireless modules, direct NAT bridge access to guest VMs may not work as expected. This network path is not the primary supported route for the follow-up automation scripts in this project.</p><p>Known successful wireless-module setups on PVE require router-side DHCP (<code>automatically obtain an IP address</code>) or equivalent static-route adjustments. For Wi-Fi routers using strict fixed-IP uplink mode, there are currently no stable success cases.</p>`,75)]))}const m=t(n,[["render",o]]);export{u as __pageData,m as default};
